import { Effect, pipe } from "effect";
import * as TE from "fp-ts/TaskEither";

interface DomainError { readonly _tag: "DomainError"; readonly msg: string }

const taskEither: TE.TaskEither<DomainError, number> = TE.right(42);

const fromTaskEither = <E, A>(te: TE.TaskEither<E, A>): Effect.Effect<A, E> =>
  Effect.flatMap(
    Effect.promise(() => te()),
    (either) => (either._tag === "Right" ? Effect.succeed(either.right) : Effect.fail(either.left)),
  );

export const program: Effect.Effect<number, DomainError> = pipe(
  fromTaskEither(taskEither),
  Effect.map((n) => n + 1),
);
