import { Effect, Ref, pipe } from "effect";

const withMutex = <A, E>(lock: Effect.Semaphore, body: Effect.Effect<A, E>): Effect.Effect<A, E> =>
  lock.withPermits(1)(body);

export const program: Effect.Effect<number> = Effect.gen(function* () {
  const counter = yield* Ref.make(0);
  const lock = yield* Effect.makeSemaphore(1);
  const incr = withMutex(lock, Ref.update(counter, (n) => n + 1));
  yield* Effect.all([incr, incr], { concurrency: "unbounded" });
  return yield* Ref.get(counter);
});
