// trusted promise: cannot reject under normal operation
const currentTime: Effect.Effect<number> = Effect.promise(async () => Date.now());

// untrusted promise: may throw, so we type the failure
const remote = (url: string): Effect.Effect<string, HttpError> =>
  Effect.tryPromise({
    try: () => fetch(url).then((r) => r.text()),
    catch: (cause) => new HttpError({ cause }),
  });

export const program = pipe(
  Effect.all([currentTime, remote("/ping")] as const),
  Effect.map(([t, body]) => `${t}:${body.length}`),
);
```

