A defect is an unrecoverable failure outside the typed E channel — produced by Effect.die, a throw from synchronous code, or Effect.orDie. Unlike typed errors (Effect.fail), defects propagate past Effect.catchAll and Effect.catchTag; only Effect.catchAllDefect or a top-level handler can observe them. Use Effect.die to signal a bug (reached impossible branch) rather than a business-rule failure.

```typescript
import { Effect, pipe } from "effect";

type Shape = { readonly kind: "circle"; readonly r: number } | { readonly kind: "square"; readonly s: number };

export const area = (shape: Shape): Effect.Effect<number> =>
  pipe(
    Effect.succeed(shape),
    Effect.flatMap((s) => {
      switch (s.kind) {
        case "circle": return Effect.succeed(Math.PI * s.r * s.r);
        case "square": return Effect.succeed(s.s * s.s);
        default: {
          const _exhaustive: never = s;
          return Effect.die(new Error(`unreachable: ${JSON.stringify(_exhaustive)}`));
        }
      }
    }),
  );
```

