import { Effect, Duration, pipe } from "effect";

const work: Effect.Effect<string> = pipe(
  Effect.sleep(Duration.seconds(1)),
  Effect.as("done"),
);

export const program = Effect.gen(function* () {
  const cancel = yield* Effect.makeLatch(false);
  const cancelled: Effect.Effect<string, Error> = pipe(
    cancel.await,
    Effect.zipRight(Effect.fail(new Error("cancelled"))),
  );
  // in real code, something else opens the latch
  return yield* Effect.raceAll([work, cancelled]);
});
