import { Effect, Queue, pipe } from "effect";

export const program = Effect.gen(function* () {
  const q = yield* Queue.unbounded<number>();
  const sem = yield* Effect.makeSemaphore(3);

  const worker = (id: number) =>
    pipe(
      Queue.take(q),
      Effect.flatMap((n) =>
        sem.withPermits(1)(Effect.logInfo(`w${id} got ${n}`)),
      ),
      Effect.forever,
    );

  yield* Effect.forkAll([worker(1), worker(2), worker(3), worker(4)]);
  yield* Effect.all([1, 2, 3, 4, 5].map((n) => Queue.offer(q, n)));
  return q;
});
